  BY: "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 900 300\">\n  <defs>\n    <pattern id=\"by-rushnyk\" x=\"0\" y=\"0\" width=\"100\" height=\"100\" patternUnits=\"userSpaceOnUse\">\n      <rect width=\"100\" height=\"100\" fill=\"#fff\"/>\n      <g fill=\"#d22730\">\n        <path d=\"M50 8 L62 20 L50 32 L38 20 Z\"/>\n        <path d=\"M50 12 L58 20 L50 28 L42 20 Z\" fill=\"#fff\"/>\n        <rect x=\"46\" y=\"16\" width=\"8\" height=\"8\" fill=\"#d22730\"/>\n        <path d=\"M14 44 h10 v-6 h6 v-6 h6 v12 h-6 v6 h-6 v6 h-10 z\"/>\n        <path d=\"M86 44 h-10 v-6 h-6 v-6 h-6 v12 h6 v6 h6 v6 h10 z\"/>\n        <path d=\"M50 50 L60 60 L50 70 L40 60 Z\"/>\n        <path d=\"M50 55 L55 60 L50 65 L45 60 Z\" fill=\"#fff\"/>\n        <path d=\"M20 78 h12 v8 h-12 z\"/>\n        <path d=\"M68 78 h12 v8 h-12 z\"/>\n        <path d=\"M44 84 h12 v10 h-12 z\"/>\n        <path d=\"M8 30 h6 v40 h-6 z\"/>\n        <path d=\"M86 30 h6 v40 h-6 z\"/>\n      </g>\n    </pattern>\n  </defs>\n  <!-- red field to the right, top two-thirds -->\n  <rect x=\"100\" y=\"0\" width=\"800\" height=\"200\" fill=\"#d22730\"/>\n  <!-- green band bottom third, full width to x=900 -->\n  <rect x=\"100\" y=\"200\" width=\"800\" height=\"100\" fill=\"#007e3a\"/>\n  <!-- hoist ornament stripe -->\n  <rect x=\"0\" y=\"0\" width=\"100\" height=\"300\" fill=\"url(#by-rushnyk)\"/>\n</svg>",
  AG: "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 900 300\">\n  <defs>\n    <clipPath id=\"ag-center\">\n      <!-- inverted triangle / chevron: wide central band at top, converging to point at bottom center -->\n      <path d=\"M250 0 H650 V150 L450 300 L250 150 Z\"/>\n    </clipPath>\n  </defs>\n  <!-- white background -->\n  <rect width=\"900\" height=\"300\" fill=\"#fff\"/>\n  <!-- red fills entire field; center gets carved by bands -->\n  <rect width=\"900\" height=\"300\" fill=\"#ce1126\"/>\n  <!-- central section: horizontal bands, clipped to inverted-triangle shape -->\n  <g clip-path=\"url(#ag-center)\">\n    <!-- black upper band -->\n    <rect x=\"250\" y=\"0\" width=\"400\" height=\"120\" fill=\"#000001\"/>\n    <!-- blue band, full width of central section -->\n    <rect x=\"250\" y=\"120\" width=\"400\" height=\"80\" fill=\"#0072c6\"/>\n    <!-- white band, full width of central section -->\n    <rect x=\"250\" y=\"200\" width=\"400\" height=\"100\" fill=\"#fff\"/>\n    <!-- rising half-sun with rays, centered on black -->\n    <g fill=\"#fcd116\">\n      <g id=\"ag-sun\" transform=\"translate(450,120)\">\n        <!-- rays: 16 rays around, but half-sun rising so rays fan upward/outward -->\n        <g>\n          <polygon points=\"-6,-72 6,-72 0,-52\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(22.5)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(45)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(67.5)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(90)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(-22.5)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(-45)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(-67.5)\"/>\n          <polygon points=\"-6,-72 6,-72 0,-52\" transform=\"rotate(-90)\"/>\n        </g>\n        <!-- half-disc rising from the black/blue boundary (y=0 here) -->\n        <path d=\"M-44 0 A44 44 0 0 1 44 0 Z\"/>\n      </g>\n    </g>\n  </g>\n</svg>",
